import{BaseMixin}from"./base-mixin.js";class MarginMixin extends BaseMixin{constructor(i,t){super(i,t),this._margins={top:10,right:50,bottom:30,left:30}}configure(i){return super.configure(i),this}conf(){return this._conf}margins(i){return arguments.length?(this._margins=i,this):this._margins}effectiveWidth(){return this.width()-this.margins().left-this.margins().right}effectiveHeight(){return this.height()-this.margins().top-this.margins().bottom}}export{MarginMixin};